async (page) => {
  var title = "图解 Blaze · 第 2 章 · 项目搭建 — 图解 Blaze-Persistence";
  var html = "<section style=\"margin-bottom:24px;\">\n<h2 style=\"font-size:24px;font-weight:800;color:#1a1a2e;line-height:1.4;margin:0 0 8px;\">第 2 章 · 项目搭建</h2>\n</section>\n<section><p style=\"font-size:14px;color:#888;margin-bottom:28px;line-height:1.7;\">CriteriaBuilderFactory · EntityViewManager · Maven · Spring Boot Starter</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px 14px;margin:0 0 28px;line-height:1.9;\"><p style=\"font-size:15px;color:#2b2b2b;margin-bottom:10px;line-height:1.8;\">\n    Blaze-Persistence 并非一个\"加到 classpath 就能用\"的库——它需要正确初始化两个核心工厂：\n    <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilderFactory</code> 和 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewManager</code>。\n    本章用图解方式拆解完整的搭建流程，从 Maven 依赖到 Spring Boot 自动配置，帮助你在 10 分钟内跑通第一个查询。\n  </p><ul style=\"margin:8px 0 8px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:4px;font-size:13px;\">理解 Blaze-Persistence 模块拆分与依赖关系</li><li style=\"margin-bottom:4px;font-size:13px;\">掌握 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilderFactory</code> 和 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewManager</code> 的初始化流程</li><li style=\"margin-bottom:4px;font-size:13px;\">使用 Spring Boot Starter 实现零配置搭建</li><li style=\"margin-bottom:4px;font-size:13px;\">配置多数据源场景下的多工厂实例</li><li style=\"margin-bottom:4px;font-size:13px;\">规避搭建阶段最常见的 5 类陷阱</li></ul><p style=\"font-size:12px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">\n    前置阅读：<span style=\"color:#1e6fff;\">第 1 章 · 全景概览</span> — 了解 Blaze-Persistence 的定位与架构分层。\n  </p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">2.1 Maven/Gradle 依赖配置</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  Blaze-Persistence 将功能拆分为多个细粒度模块，遵循 API / 实现分离原则。\n  下图展示了核心模块之间的依赖关系——箭头方向表示\"依赖于\"。\n</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 2-1 · Blaze-Persistence 模块依赖树</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">核心查询引擎</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">core-api<br/>接口 & SPI</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">core-impl<br/>JPQL 生成器</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">core-impl-hibernate<br/>Hibernate 集成适配</p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">Entity View 投影</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">entity-view-api<br/>注解 & 接口</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">entity-view-impl<br/>运行时映射</p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">Spring 集成</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">integration-spring-data<br/>Repository 支持</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">spring-boot-starter<br/>自动配置</p></section></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">blaze-persistence-bom<br/>版本统一管理</p></section></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  理解这张图之后，你只需根据项目需求选择引入哪些模块。最小可用集合是\n  <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">core-api</code> + <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">core-impl</code> + <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">core-impl-hibernate</code>；\n  如果需要 Entity View 则追加 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">entity-view-api</code> + <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">entity-view-impl</code>。\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">版本 BOM</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">推荐使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">blaze-persistence-bom</code> 统一管理版本号，避免模块间版本不一致：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">&lt;!-- pom.xml --&gt;<br/>&lt;dependencyManagement&gt;<br/>  &lt;dependencies&gt;<br/>    &lt;dependency&gt;<br/>      &lt;groupId&gt;com.blazebit&lt;/groupId&gt;<br/>      &lt;artifactId&gt;blaze-persistence-bom&lt;/artifactId&gt;<br/>      &lt;version&gt;1.6.11&lt;/version&gt;<br/>      &lt;type&gt;pom&lt;/type&gt;<br/>      &lt;scope&gt;import&lt;/scope&gt;<br/>    &lt;/dependency&gt;<br/>  &lt;/dependencies&gt;<br/>&lt;/dependencyManagement&gt;<br/><br/>&lt;dependencies&gt;<br/>  &lt;!-- 核心查询引擎 --&gt;<br/>  &lt;dependency&gt;<br/>    &lt;groupId&gt;com.blazebit&lt;/groupId&gt;<br/>    &lt;artifactId&gt;blaze-persistence-core-api&lt;/artifactId&gt;<br/>    &lt;scope&gt;compile&lt;/scope&gt;<br/>  &lt;/dependency&gt;<br/>  &lt;dependency&gt;<br/>    &lt;groupId&gt;com.blazebit&lt;/groupId&gt;<br/>    &lt;artifactId&gt;blaze-persistence-core-impl&lt;/artifactId&gt;<br/>    &lt;scope&gt;runtime&lt;/scope&gt;<br/>  &lt;/dependency&gt;<br/>  &lt;dependency&gt;<br/>    &lt;groupId&gt;com.blazebit&lt;/groupId&gt;<br/>    &lt;artifactId&gt;blaze-persistence-core-impl-hibernate-6.2&lt;/artifactId&gt;<br/>    &lt;scope&gt;runtime&lt;/scope&gt;<br/>  &lt;/dependency&gt;<br/><br/>  &lt;!-- Entity View 投影（可选） --&gt;<br/>  &lt;dependency&gt;<br/>    &lt;groupId&gt;com.blazebit&lt;/groupId&gt;<br/>    &lt;artifactId&gt;blaze-persistence-entity-view-api&lt;/artifactId&gt;<br/>    &lt;scope&gt;compile&lt;/scope&gt;<br/>  &lt;/dependency&gt;<br/>  &lt;dependency&gt;<br/>    &lt;groupId&gt;com.blazebit&lt;/groupId&gt;<br/>    &lt;artifactId&gt;blaze-persistence-entity-view-impl&lt;/artifactId&gt;<br/>    &lt;scope&gt;runtime&lt;/scope&gt;<br/>  &lt;/dependency&gt;<br/><br/>  &lt;!-- Spring Data 集成（可选） --&gt;<br/>  &lt;dependency&gt;<br/>    &lt;groupId&gt;com.blazebit&lt;/groupId&gt;<br/>    &lt;artifactId&gt;blaze-persistence-integration-spring-data-3.3&lt;/artifactId&gt;<br/>  &lt;/dependency&gt;<br/>&lt;/dependencies&gt;</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 2-2 · scope 规则：API compile、实现 runtime</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">core</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">api</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">impl</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">entity</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">view</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">你的应用代码</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">core-api<br/>compile</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">core-impl<br/>runtime</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">core-impl-hibernate<br/>runtime</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">entity-view-api<br/>compile</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">entity-view-impl<br/>runtime</p></section></td></tr></table></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 为什么 impl 是 runtime？</strong>\n  应用代码只依赖 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">core-api</code> 和 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">entity-view-api</code> 中的接口与注解。\n  实现类通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ServiceLoader</code> 在运行时自动发现，确保编译期零耦合。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">2.2 CriteriaBuilderFactory 初始化</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilderFactory</code> 是 Blaze-Persistence 的查询入口——\n  所有 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilder</code> 实例都从它创建。\n  它的初始化遵循 <strong style=\"color:#1a1a2e;font-weight:700;\">Configuration → Factory</strong> 模式：先通过可变的配置对象注册属性，\n  然后调用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">createCriteriaBuilderFactory()</code> 生成不可变的工厂实例。\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">生命周期</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 2-3 · CriteriaBuilderFactory 初始化时序图</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">应用启动</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityManagerFactory</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">CriteriaBuilderConfiguration</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">ServiceLoader</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">CriteriaBuilderFactory</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 此后 CBF 不可修改[BR]可在多线程间共享</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 线程安全保证</strong>\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilderFactory</code> 创建后是不可变的（immutable），\n  可以安全地作为单例存储在 Spring 容器或静态字段中，供任意线程并发调用。\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">代码示例：手动初始化</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 1. 获取 JPA EntityManagerFactory（通常来自 persistence.xml）</span><br/>EntityManagerFactory emf =<br/>    Persistence.createEntityManagerFactory(\"my-pu\");<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 2. 创建 CriteriaBuilderConfiguration</span><br/>CriteriaBuilderConfiguration config =<br/>    Criteria.getDefault();<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 3. 可选：注册自定义配置</span><br/>config.setProperty(<br/>    ConfigurationProperties.COMPATIBLE_MODE,<br/>    \"false\"<br/>);<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 4. 构建不可变工厂</span><br/>CriteriaBuilderFactory cbf =<br/>    config.createCriteriaBuilderFactory(emf);<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 5. 使用 —— 从 cbf 创建查询</span><br/>CriteriaBuilder&lt;Cat&gt; cb = cbf.create(em, Cat.class);<br/>List&lt;Cat&gt; cats = cb.where(\"age\").gt(3).getResultList();</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 2-4 · CriteriaBuilderFactory 内部组件</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">内部组件</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JPA 元模型缓存<br/>实体/属性映射</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">自定义函数注册表<br/>JPQL 函数扩展</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">数据库方言<br/>SQL 差异适配</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">配置属性<br/>行为开关</p></section></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CriteriaBuilderFactory<br/>不可变单例</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CriteriaBuilder #1</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CriteriaBuilder #2</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CriteriaBuilder #3</p></section></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">2.3 EntityViewManager 初始化</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewManager</code> 是 Entity View 子系统的核心工厂。\n  它扫描并注册所有带 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EntityView</code> 注解的接口/抽象类，\n  然后生成运行时代理。初始化流程同样遵循 Configuration → Factory 模式。\n</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 2-5 · EntityViewManager 初始化流程</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">addEntityView(CatView.class)<br/>addEntityView(PersonView.class)<br/>...逐个注册</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">逐个注册</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">com</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">demo</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">创建 EntityViewConfiguration</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 扫描方式？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">addEntityViewPackage('com.demo.view')<br/>自动发现 @EntityView 类</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">验证映射一致性<br/>属性名 ↔ 实体字段</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">createEntityViewManager(cbf)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">抛出 IllegalArgumentException<br/>包含详细映射错误</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityViewManager<br/>不可变 · 线程安全</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">apply(setting, query)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">convert(entity, ViewClass)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">saveFull(em, view)</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">两种注册方式对比</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#e05252;margin-bottom:8px;\">❌ 错误示范</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">EntityViewConfiguration cfg =<br/>    EntityViews.createDefaultConfiguration();<br/><br/>cfg.addEntityView(CatView.class);<br/>cfg.addEntityView(PersonView.class);<br/>cfg.addEntityView(OrderSummary.class);<br/><span style=\"color:#6c7086;font-style:italic;\">// ... 每新增一个 View 都要加一行</span><br/><br/>EntityViewManager evm =<br/>    cfg.createEntityViewManager(cbf);</p><p style=\"font-size:13px;color:#2b2b2b;margin-bottom:6px;\">适合微型项目或测试场景，但随着 View 数量增加维护成本线性增长。</p></section><section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#1e6fff;margin-bottom:8px;\">✅ 正确做法</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">EntityViewConfiguration cfg =<br/>    EntityViews.createDefaultConfiguration();<br/><br/>cfg.addEntityViewPackage(\"com.demo.view\");<br/><br/>EntityViewManager evm =<br/>    cfg.createEntityViewManager(cbf);</p><p style=\"font-size:13px;color:#2b2b2b;margin-bottom:6px;\">推荐方式——新增 View 无需修改配置代码，扫描器自动发现所有 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EntityView</code> 类。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 2-6 · EntityView 扫描与代理生成</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">扫描发现</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">CatView<br/>@EntityView(Cat.class)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">PersonView<br/>@EntityView(Person.class)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">OrderSummary<br/>@EntityView(Order.class)</p></section></td></tr></table></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">com.demo.view 包</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityViewManager<br/>内部注册表</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CatView$Proxy<br/>运行时生成</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">PersonView$Proxy<br/>运行时生成</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">OrderSummary$Proxy<br/>运行时生成</p></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">⚠️ 顺序陷阱</strong>\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewManager</code> 必须在所有 Entity View 注册完毕之后再调用\n  <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">createEntityViewManager(cbf)</code>——创建后不可追加新的 View 类。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">2.4 Spring Boot Auto-Configuration</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  如果项目使用 Spring Boot，引入 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">blaze-persistence-integration-spring-boot-starter</code>\n  即可省去所有手动初始化代码。Starter 通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@AutoConfiguration</code> 自动完成以下工作：\n</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 2-7 · Spring Boot Starter 自动配置链</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">entity</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">view</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">spring</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">data</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">BlazeAutoConfiguration<br/>@AutoConfiguration</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 检测到<br/>EntityManagerFactory?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">跳过 Blaze 配置</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">注册 Bean:<br/>CriteriaBuilderFactory</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ classpath 含<br/>entity-view-impl?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">扫描 @EntityView<br/>基于 @EntityScan 包路径</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">注册 Bean:<br/>EntityViewManager</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ classpath 含<br/>spring-data 集成?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">启用<br/>EntityViewRepository<br/>支持</p></section></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">整个过程只需两步：添加依赖，写 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">application.yml</code>。</p></section>\n<section><h4 style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">最小依赖配置</h4></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">&lt;!-- pom.xml —— 一个 Starter 搞定一切 --&gt;<br/>&lt;dependency&gt;<br/>  &lt;groupId&gt;com.blazebit&lt;/groupId&gt;<br/>  &lt;artifactId&gt;blaze-persistence-integration-spring-boot-starter&lt;/artifactId&gt;<br/>  &lt;version&gt;1.6.11&lt;/version&gt;<br/>&lt;/dependency&gt;</p></section>\n<section><h4 style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">application.yml 属性</h4></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\"># application.yml</span><br/>blaze:<br/>  persistence:<br/><span style=\"color:#6c7086;font-style:italic;\">    # Entity View 扫描包（默认与 @SpringBootApplication 相同）</span><br/>    view:<br/>      entity-view-packages: com.demo.view<br/><span style=\"color:#6c7086;font-style:italic;\">    # 可选：全局配置属性</span><br/>    properties:<br/>      com.blazebit.persistence.returning_clause_enabled: \"true\"</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">手动 vs 自动配置对比</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 2-8 · 代码量对比：手动初始化 vs Spring Boot Starter</p><section style=\"margin:3px 0;padding:8px 12px;background:rgb(248,81,73);border-left:3px solid #f85149;border-radius:4px;\"><p style=\"margin:0;font-size:12px;line-height:1.6;\"><span style=\"color:#f85149;\">❌ 手动初始化 · ~25 行</span> <span style=\"color:#2b2b2b;\">创建 EMF↓Criteria.getDefault()↓设置属性↓createCriteriaBuilderFactory()↓EntityViews 配置 + 包扫描↓createEntityViewManager()↓注册到容器</span></p></section><section style=\"margin:3px 0;padding:8px 12px;background:rgb(63,185,80);border-left:3px solid #3fb950;border-radius:4px;\"><p style=\"margin:0;font-size:12px;line-height:1.6;\"><span style=\"color:#3fb950;\">✅ Spring Boot · ~2 行</span> <span style=\"color:#2b2b2b;\">添加 Starter 依赖↓配置 yml</span> <span style=\"color:#3fb950;\">自动检测 EMF · 自动扫描 View · 自动注册 Bean</span></p></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#e05252;margin-bottom:8px;\">❌ 错误示范</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@Configuration<br/>public class BlazePersistenceConfig {<br/><br/>  @PersistenceUnit<br/>  private EntityManagerFactory emf;<br/><br/>  @Bean<br/>  @Scope(SCOPE_SINGLETON)<br/>  @Lazy(false)<br/>  public CriteriaBuilderFactory cbf() {<br/>    CriteriaBuilderConfiguration cfg =<br/>        Criteria.getDefault();<br/>    cfg.setProperty(...);<br/>    return cfg<br/>      .createCriteriaBuilderFactory(emf);<br/>  }<br/><br/>  @Bean<br/>  @Scope(SCOPE_SINGLETON)<br/>  @Lazy(false)<br/>  public EntityViewManager evm(<br/>      CriteriaBuilderFactory cbf) {<br/>    EntityViewConfiguration cfg =<br/>        EntityViews.createDefaultConfiguration();<br/>    cfg.addEntityViewPackage(<br/>        \"com.demo.view\");<br/>    return cfg<br/>      .createEntityViewManager(cbf);<br/>  }<br/>}</p></section><section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#1e6fff;margin-bottom:8px;\">✅ 正确做法</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">&lt;!-- pom.xml --&gt;<br/>&lt;dependency&gt;<br/>  &lt;groupId&gt;com.blazebit&lt;/groupId&gt;<br/>  &lt;artifactId&gt;blaze-persistence-integration<br/>    -spring-boot-starter&lt;/artifactId&gt;<br/>&lt;/dependency&gt;</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\"># application.yml</span><br/>blaze:<br/>  persistence:<br/>    view:<br/>      entity-view-packages:<br/>        com.demo.view</p><p style=\"font-size:13px;color:#2b2b2b;margin-bottom:6px;\">\n      Starter 自动检测 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityManagerFactory</code>，\n      自动扫描 Entity View，自动注册所有 Bean。\n    </p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">2.5 多数据源配置</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  在微服务或多租户架构中，一个应用可能需要连接多个数据库。\n  此时需要为每个 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityManagerFactory</code> 创建独立的\n  <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilderFactory</code> 和 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewManager</code>。\n</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 2-9 · 多数据源架构：每个数据源独立工厂链</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">数据源 A · 订单库</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">DataSource A<br/>jdbc:mysql://order-db</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityManagerFactory A</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CriteriaBuilderFactory A</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityViewManager A<br/>OrderView, ItemView</p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">数据源 B · 用户库</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">DataSource B<br/>jdbc:postgresql://user-db</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityManagerFactory B</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CriteriaBuilderFactory B</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityViewManager B<br/>UserView, RoleView</p></section></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Spring Boot 应用</p></section></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Qualifier</code> 区分多个工厂 Bean：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@Configuration<br/>public class MultiDataSourceBlazeConfig {<br/><br/>    @Bean @Qualifier(\"order\")<br/>    public CriteriaBuilderFactory orderCbf(<br/>            @Qualifier(\"order\") EntityManagerFactory emf) {<br/>        return Criteria.getDefault()<br/>            .createCriteriaBuilderFactory(emf);<br/>    }<br/><br/>    @Bean @Qualifier(\"user\")<br/>    public CriteriaBuilderFactory userCbf(<br/>            @Qualifier(\"user\") EntityManagerFactory emf) {<br/>        return Criteria.getDefault()<br/>            .createCriteriaBuilderFactory(emf);<br/>    }<br/><br/>    @Bean @Qualifier(\"order\")<br/>    public EntityViewManager orderEvm(<br/>            @Qualifier(\"order\") CriteriaBuilderFactory cbf) {<br/>        EntityViewConfiguration cfg =<br/>            EntityViews.createDefaultConfiguration();<br/>        cfg.addEntityViewPackage(\"com.demo.order.view\");<br/>        return cfg.createEntityViewManager(cbf);<br/>    }<br/><br/>    @Bean @Qualifier(\"user\")<br/>    public EntityViewManager userEvm(<br/>            @Qualifier(\"user\") CriteriaBuilderFactory cbf) {<br/>        EntityViewConfiguration cfg =<br/>            EntityViews.createDefaultConfiguration();<br/>        cfg.addEntityViewPackage(\"com.demo.user.view\");<br/>        return cfg.createEntityViewManager(cbf);<br/>    }<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">⚠️ Entity View 不能跨工厂共享</strong>\n  一个 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewManager</code> 只认识它注册时所绑定的\n  <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilderFactory</code>。\n  跨数据源使用错误的 EVM 会导致运行时异常。\n</section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 2-10 · 多数据源 Bean 注入关系</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">订单服务</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">OrderService</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">orderCbf</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">orderEvm</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">用户服务</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">UserService</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">userCbf</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">userEvm</p></section></td></tr></table></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">orderEmf</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">userEmf</p></section></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">2.6 陷阱与限制</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  搭建阶段的错误往往在运行时才暴露，且异常信息不够直观。\n  下面梳理最常见的 5 类陷阱及其解决方案。\n</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 2-11 · 搭建阶段常见陷阱决策树</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">core</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">impl</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">persistence</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">xml</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Blaze</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Persistence</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ ClassNotFoundException<br/>或 NoClassDefFoundError?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">检查 impl 模块是否在 classpath<br/>core-impl / entity-view-impl</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ IllegalArgumentException<br/>映射验证失败?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">检查 @EntityView 注解的<br/>实体类是否在 persistence.xml</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ NoSuchMethodError<br/>或 AbstractMethodError?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Hibernate 与 Blaze-Persistence<br/>版本不兼容 → 查兼容矩阵</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ Spring Bean<br/>创建失败?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">确认 EMF Bean 先于<br/>CBF Bean 初始化</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 查询时 NPE<br/>或 LazyInitException?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">确认 EntityManager<br/>在事务上下文内使用</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 1：版本不匹配</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  Blaze-Persistence 对 Hibernate 版本有严格要求，使用错误的集成模块会触发\n  <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">NoSuchMethodError</code>。\n</p></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">Blaze-Persistence</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">Hibernate 版本</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">集成模块 artifactId</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">1.6.x</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">5.6.x</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">core-impl-hibernate-5.6</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">1.6.x</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">6.2.x</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">core-impl-hibernate-6.2</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">1.6.x</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">6.4.x+</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">core-impl-hibernate-6.2</code> (兼容)</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">1.5.x</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">5.4.x</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">core-impl-hibernate-5.4</code></td></tr></table></section>\n<section style=\"background:#f5f5f5;border:1px solid #e6a81744;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">🔧 排查技巧</strong>\n  在 Maven 中运行 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">mvn dependency:tree | grep hibernate</code> 确认实际传递的 Hibernate 版本，\n  然后对照上表选择正确的集成模块。\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 2：EntityView 注册遗漏</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 2-12 · 未注册 EntityView 的错误链路</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">应用</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityViewManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">CriteriaBuilder</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 原因：CatView 未通过[BR]addEntityView() 或包扫描注册</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 3：Spring Bean 初始化顺序</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilderFactory</code> 依赖 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityManagerFactory</code>，\n  <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewManager</code> 依赖 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilderFactory</code>。\n  如果使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Lazy</code> 或条件装配，可能打断依赖链。\n</p></section>\n<section style=\"margin:16px 0;padding:14px 16px;background:#f5f5f5;border-radius:8px;border:1px solid #e5e7eb;\"><p style=\"margin:0 0 8px;\"><span style=\"display:inline-block;width:28px;height:28px;background:#1e6fff;color:#fff;border-radius:50%;text-align:center;line-height:28px;font-weight:700;font-size:14px;\">1</span></p><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">EntityManagerFactory</strong> 必须最先就绪（由 Spring JPA 自动配置保证）\n    </p></section>\n<section style=\"margin:16px 0;padding:14px 16px;background:#f5f5f5;border-radius:8px;border:1px solid #e5e7eb;\"><p style=\"margin:0 0 8px;\"><span style=\"display:inline-block;width:28px;height:28px;background:#1e6fff;color:#fff;border-radius:50%;text-align:center;line-height:28px;font-weight:700;font-size:14px;\">2</span></p><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">CriteriaBuilderFactory</strong> 在 EMF 之后创建，标记 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Lazy(false)</code>\n</p></section>\n<section style=\"margin:16px 0;padding:14px 16px;background:#f5f5f5;border-radius:8px;border:1px solid #e5e7eb;\"><p style=\"margin:0 0 8px;\"><span style=\"display:inline-block;width:28px;height:28px;background:#1e6fff;color:#fff;border-radius:50%;text-align:center;line-height:28px;font-weight:700;font-size:14px;\">3</span></p><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">EntityViewManager</strong> 在 CBF 之后创建，同样 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Lazy(false)</code>\n</p></section>\n<section style=\"margin:16px 0;padding:14px 16px;background:#f5f5f5;border-radius:8px;border:1px solid #e5e7eb;\"><p style=\"margin:0 0 8px;\"><span style=\"display:inline-block;width:28px;height:28px;background:#1e6fff;color:#fff;border-radius:50%;text-align:center;line-height:28px;font-weight:700;font-size:14px;\">4</span></p><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">业务 Service / Repository</strong> 最后注入 CBF 和 EVM\n    </p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 4：Spring Boot Starter 版本选择</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  Starter 模块的命名从 1.6.9 开始区分 Spring Boot 2.x 和 3.x。\n  使用错误版本将导致自动配置完全失效但不报错。\n</p></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">Spring Boot</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">Starter artifactId</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">2.7.x</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">blaze-persistence-integration-spring-boot-starter</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">3.0 ~ 3.3</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">blaze-persistence-integration-spring-boot-3.1-starter</code></td></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 5：scope 误用</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">图 2-13 · scope 误用导致编译失败场景</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n❌ 错误：API 用 runtime\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">core-api</code> → runtime\n编译错误：cannot find symbol CriteriaBuilder\n\n\n✅ 正确：API 用 compile\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">core-api</code> → compile\nCriteriaBuilder 正常引用\n\n\n⚠️ 警告：impl 用 compile\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">core-impl</code> → compile\n不影响编译，但违反封装原则\n\n</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 黄金法则</strong>\n  API 模块（<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">core-api</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">entity-view-api</code>）用\n  <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">compile</code> scope；\n  实现模块（<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">core-impl</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">entity-view-impl</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">core-impl-hibernate-*</code>）用\n  <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">runtime</code> scope。\n</section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px;margin:36px 0 16px;\"><p style=\"font-size:18px;font-weight:700;color:#1e6fff;margin:0 0 12px;\">📋 📝 本章小结</p><ul style=\"margin:8px 0 12px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:5px;font-size:14px;\">Blaze-Persistence 采用<strong style=\"color:#1a1a2e;font-weight:700;\">模块化设计</strong>，通过 BOM 统一版本，API 与实现分离</li><li style=\"margin-bottom:5px;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilderFactory</code> 是查询入口，创建后<strong style=\"color:#1a1a2e;font-weight:700;\">不可变且线程安全</strong></li><li style=\"margin-bottom:5px;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewManager</code> 负责 DTO 投影，需在所有 View 注册后一次性构建</li><li style=\"margin-bottom:5px;font-size:14px;\">Spring Boot Starter 将 ~25 行配置代码缩减为 <strong style=\"color:#1a1a2e;font-weight:700;\">2 行依赖 + yml</strong></li><li style=\"margin-bottom:5px;font-size:14px;\">多数据源场景需要为每个 DataSource 创建<strong style=\"color:#1a1a2e;font-weight:700;\">独立的工厂链</strong></li><li style=\"margin-bottom:5px;font-size:14px;\">最常见的 5 类陷阱：版本不匹配、View 未注册、Bean 顺序、Starter 版本选错、scope 误用</li></ul><p style=\"font-size:13px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">\n    下一章 <span style=\"color:#1e6fff;\">第 3 章 · CriteriaBuilder 查询引擎</span>\n    将深入 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilder</code> 的类型安全查询构建机制——\n    从 WHERE / ORDER BY 到动态条件拼接，全部以 Mermaid 图解呈现。\n  </p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">© 2026 图解 Blaze-Persistence · 第 2 章 · 项目搭建</p></section>";
  await page.waitForSelector('.ProseMirror', { timeout: 15000 });
  if (title) {
    var ti = page.locator('textarea[placeholder="请在这里输入标题"]');
    await ti.fill(title);
    await page.waitForTimeout(300);
  }
  await page.evaluate((h) => {
    var pm = document.querySelector('.ProseMirror');
    pm.focus();
    var dt = new DataTransfer();
    dt.setData('text/html', h);
    var ev = new ClipboardEvent('paste', {bubbles:true, cancelable:true, clipboardData:dt});
    pm.dispatchEvent(ev);
  }, html);
  await page.waitForTimeout(1500);
  var enableBtns = page.locator('label:has-text("开启")');
  var cnt = await enableBtns.count();
  for (var i = 0; i < cnt; i++) {
    try {
      var b = enableBtns.nth(i);
      if (await b.isVisible({ timeout: 500 })) await b.click({ timeout: 1000 });
    } catch(e) {}
  }
  await page.waitForTimeout(500);
  var saveBtn = page.getByRole('button', { name: '保存为草稿' });
  await saveBtn.click();
  await page.waitForTimeout(2000);
  return title + ' -> saved';
}